// Generate LinkedIn job search URLs for UK visa-sponsored roles
// Focus on micro-SME companies with ≤100 employees
const searchUrls = [
  // Skilled Worker visa-friendly roles at small companies
  'https://www.linkedin.com/jobs/search/?keywords=visa%20sponsorship&location=United%20Kingdom&f_TPR=r604800&f_CS=2&sortBy=DD',
  'https://www.linkedin.com/jobs/search/?keywords=sponsor%20visa&location=United%20Kingdom&f_TPR=r604800&f_CS=2&sortBy=DD',
  'https://www.linkedin.com/jobs/search/?keywords=skilled%20worker%20visa&location=United%20Kingdom&f_TPR=r604800&f_CS=2&sortBy=DD',
  // Tech roles at small companies
  'https://www.linkedin.com/jobs/search/?keywords=software%20developer%20sponsorship&location=United%20Kingdom&f_TPR=r604800&f_CS=2&sortBy=DD',
  'https://www.linkedin.com/jobs/search/?keywords=data%20analyst%20visa%20sponsor&location=United%20Kingdom&f_TPR=r604800&f_CS=2&sortBy=DD',
  // Graduate-friendly roles
  'https://www.linkedin.com/jobs/search/?keywords=graduate%20visa%20sponsorship&location=United%20Kingdom&f_TPR=r604800&f_CS=2&sortBy=DD',
  'https://www.linkedin.com/jobs/search/?keywords=junior%20developer%20sponsorship&location=London&f_TPR=r604800&f_CS=2&sortBy=DD',
  // Finance and business roles
  'https://www.linkedin.com/jobs/search/?keywords=accountant%20visa%20sponsorship&location=United%20Kingdom&f_TPR=r604800&f_CS=2&sortBy=DD',
  'https://www.linkedin.com/jobs/search/?keywords=marketing%20visa%20sponsor&location=United%20Kingdom&f_TPR=r604800&f_CS=2&sortBy=DD'
];

return [{ json: { urls: searchUrls } }];

// Filter and transform LinkedIn job results for MicroSponsor AI
// Focus on small companies (≤100 employees) that are likely visa sponsors
const items = $input.all();
const jobs = [];

for (const item of items) {
  const d = item.json;

  // Extract company size - filter for micro-SMEs
  let employeeCount = 50; // default
  const companySize = d.companySize || d.company?.employeeCount || '';
  if (typeof companySize === 'string') {
    const match = companySize.match(/(\d+)/);
    if (match) employeeCount = parseInt(match[1]);
  } else if (typeof companySize === 'number') {
    employeeCount = companySize;
  }

  // Skip large companies (>100 employees)
  if (employeeCount > 100) continue;

  // Extract salary info
  let salaryMin = 25000;
  let salaryMax = 40000;
  const salary = d.salary || d.salaryInfo || '';
  if (typeof salary === 'string') {
    const nums = salary.match(/[\d,]+/g);
    if (nums && nums.length >= 2) {
      salaryMin = parseInt(nums[0].replace(/,/g, ''));
      salaryMax = parseInt(nums[1].replace(/,/g, ''));
    } else if (nums && nums.length === 1) {
      salaryMin = parseInt(nums[0].replace(/,/g, ''));
      salaryMax = salaryMin + 10000;
    }
  }

  // Build job object
  jobs.push({
    company: d.companyName || d.company?.name || 'Unknown',
    jobTitle: d.title || d.jobTitle || 'Unknown Role',
    location: d.location || d.jobLocation || 'United Kingdom',
    employeeCount: employeeCount,
    salaryMin: salaryMin,
    salaryMax: salaryMax,
    companyDescription: d.companyDescription || d.company?.description || '',
    industry: d.companyIndustry || d.company?.industry || 'Technology',
    linkedinUrl: d.url || d.jobUrl || '',
    companyLinkedinUrl: d.companyUrl || d.company?.url || '',
    linkedinDescription: (d.description || d.jobDescription || '').substring(0, 2000),
    hiringManager: d.posterName || d.recruiter?.name || 'Hiring Manager',
    hiringManagerEmail: d.posterEmail || '',
    isNewEntrantFriendly: true,
    postedDays: 0
  });
}

return [{ json: { jobs: jobs, totalFound: jobs.length } }];
